            OpenBuyTrade();
        }

        // Check for Sell Condition
        if (rsi_current > rsiOverbought && Close[1] > upper_band) {
            OpenSellTrade();
        }

        // Close buy and sell conditions
        if (closeOnBollinger) {
            CloseBuyTrades(upper_band);
            CloseSellTrades(lower_band);
        }
    }
